import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const l={};function d(r,s){return n(),i("div",null,s[0]||(s[0]=[a(`<p>Browser Object Model浏览器对象模型，允许JavaScript与浏览器对话，JavaScript将浏览器的各个组成部分封装为对象。</p><h3 id="组成" tabindex="-1"><a class="header-anchor" href="#组成"><span>组成</span></a></h3><ul><li>Window：浏览器窗口对象 所有html作用的区域就是浏览器窗口对象</li><li>Navigator:浏览器对象 整个浏览器中的所有内容</li><li>Screen:屏幕对象</li><li>History：历史记录对象 前进或后退刷新历史记录等属于</li><li>Location：地址栏对象 输入地址的框</li></ul><h4 id="window" tabindex="-1"><a class="header-anchor" href="#window"><span>Window</span></a></h4><p>使用window类名调用</p><p>其中window对象是默认加载进去的,所以在调用window对象时可以省略window类名 如alert直接使用</p><p>函数:</p><ul><li>alert()：显示带有一段消息和一个确认按钮的警告框。</li><li>confirm():：显示带有一段消息以及确认按钮和取消按钮的对话框。</li><li>setlnterval():按照指定的周期（以毫秒计）来调用函数或计算表达式。传入的是一个函数</li><li>setTimeout():1在指定的毫秒数后调用函数或计算表达式。传入的是一个函数</li></ul><h4 id="location" tabindex="-1"><a class="header-anchor" href="#location"><span>Location</span></a></h4><p>属于Window对象中 使用window.location获取，其中window.可以省略。</p><p>属性:</p><ul><li>href : 设置或返回完整的url</li></ul><p>window对象是一个全局对象，也可以说是JavaScript中的顶级对象 所有通过var定义在全局作用域中的变量、函数都会变成window对象的属性和方法 window对象下的属性和方法调用的时候可以省略window</p><h1 id="定时器-延时函数" tabindex="-1"><a class="header-anchor" href="#定时器-延时函数"><span>定时器-延时函数</span></a></h1><p>仅仅只执行一次，</p><p><strong>设置延时函数</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>setTimeout(回调函数,等待的毫秒数)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>清除延时函数</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let timer= setTimeout(回调函数,等待的毫秒数)</span></span>
<span class="line"><span>clearTimeout(timer)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>延时器需要等待，所以后面的代码先执行 每一次调用延时器都会产生一个新的延时器</p><h1 id="js执行机制" tabindex="-1"><a class="header-anchor" href="#js执行机制"><span>js执行机制</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>console.log(1111)</span></span>
<span class="line"><span>setTimeout(function(){</span></span>
<span class="line"><span>	console.1og(2222)</span></span>
<span class="line"><span>},1000)</span></span>
<span class="line"><span>console.log(3333)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>console.log(1111)</span></span>
<span class="line"><span>setTimeout(function(){</span></span>
<span class="line"><span>	console.1og(2222)</span></span>
<span class="line"><span>}, 0)</span></span>
<span class="line"><span>console.1og(3333)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>以上两段代码执行结果都是一样的,即1111,2222,3333</p><p>JavaScript语言的一大特点就是单线程，也就是说，同一个时间只能做一件事。 这是因为Javascript这门脚本语言诞生的使命所致一一JavaScript是为处理页面中用户的交互，以及操作DOM 而诞生的。比如我们对某个DOM元素进行添加和删除操作，不能同时进行。应该先进行添加，之后再删除。 单线程就意味着，所有任务需要排队，前一个任务结束，才会执行后一个任务。这样所导致的问题是：如果JS执行的时间过长，这样就会造成页面的渲染不连贯，导致页面渲染加载阻塞的感觉。</p><p>为了解决这个问题，利用多核CPU的计算能力，HTML5提出WebWorker标准，允许JavaScript脚本创建多个线程。于是，JS中出现了同步和异步。</p><p><strong>因此js的执行过程是这样的:</strong></p><ol><li>先执行执行栈中的同步任务。</li><li>异步任务放入任务队列中。</li><li>一旦执行栈中的所有同步任务执行完毕，系统就会按次序读取任务队列中的异步任务，于是被读取的异步任务结束等待状态，进入执行栈，开始执行。</li></ol><p>js本质还是单线程的,只不过遇到了异步任务先把它交给浏览器,由浏览器控制(浏览器是可以异步的),跳过异步任务先执行完同步任务后再执行异步任务</p><p>由于主线程不断的重复获得任务、执行任务、再获取任务、再执行，所以这种机制被称为事件循环（eventloop）。</p><h1 id="location-1" tabindex="-1"><a class="header-anchor" href="#location-1"><span>location</span></a></h1><p>location的数据类型是对象，它拆分并保存了URL地址的各个组成部分</p><h3 id="href" tabindex="-1"><a class="header-anchor" href="#href"><span>href</span></a></h3><p>href属性获取完整的URL地址，对其赋值时用于地址的跳转</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>location.href=&#39;http://www.baidu.com&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>执行到这段代码立即跳转</p><h3 id="hash" tabindex="-1"><a class="header-anchor" href="#hash"><span>hash</span></a></h3><p>hash属性获取地址中的哈希值，符号#后面部分</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>console.log(location.hash)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>后期vue路由的铺垫，经常用于不刷新页面，显示不同页面</p><h3 id="常用属性和方法" tabindex="-1"><a class="header-anchor" href="#常用属性和方法"><span>常用属性和方法</span></a></h3><p>reload方法用来刷新当前页面，传入参数true时表示强制刷新</p><h1 id="navigator" tabindex="-1"><a class="header-anchor" href="#navigator"><span>navigator</span></a></h1><p>navigator的数据类型是对象，该对象下记录了浏览器自身的相关信息</p><p>常用属性和方法： 通过userAgent检测浏览器的版本及平台</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//检测userAgent（浏览器信息）</span></span>
<span class="line"><span>!(function (){</span></span>
<span class="line"><span>	constuserAgent=navigator.userAgent</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	//验证是否为Android或iPhone</span></span>
<span class="line"><span>	const android =userAgent.match(/(Android);?[¥s¥/]+([￥d.]+)?/)</span></span>
<span class="line"><span>	const iphone = userAgent.match(/(iPhone#sOS)¥s([￥d_]+)/)</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	//如果是Android或iPhone，，则跳转至移动站点</span></span>
<span class="line"><span>	if (android Il iphone) {</span></span>
<span class="line"><span>		location.href =&#39;http://m.itcast.cn&#39;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>})()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="histroy" tabindex="-1"><a class="header-anchor" href="#histroy"><span>histroy</span></a></h3><p>记录了浏览历史,有多个方法可进行操作</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>history.back()//后退</span></span>
<span class="line"><span>history.go(-1)//后退</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="本地存储" tabindex="-1"><a class="header-anchor" href="#本地存储"><span>本地存储</span></a></h1><p>随着互联网的快速发展，基于网页的应用越来越普遍，同时也变的越来越复杂，为了满足各种各样的需求，会经常性在本地存储大量的数据，HTML5规范提出了相关解决方案。</p><ol><li>数据存储在用户浏览器中</li><li>设置、读取方便、甚至页面刷新不丢失数据</li><li>容量较大，sessionStorage和localStorage约5M左右</li></ol><h2 id="本地存储分类" tabindex="-1"><a class="header-anchor" href="#本地存储分类"><span>本地存储分类</span></a></h2><h3 id="localstorage" tabindex="-1"><a class="header-anchor" href="#localstorage"><span>localStorage</span></a></h3><p>可以将数据永久存储在本地（用户的电脑），除非手动删除，否则关闭页面也会存在</p><p>可以多窗口（页面）共享（同一浏览器可以共享） 以键值对的形式存储使用</p><p>存储后是按域名分类的,不同域名之间无法获取对方的数据</p><p><strong>存储一个键值对的数据</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>localStorage.setItem(&#39;键&#39;,&#39;值&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>读取数据</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>localStorage.getItem(&#39;键&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>删除数据</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>localStorage.removeltem(&#39;键&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="存储复杂数据类型" tabindex="-1"><a class="header-anchor" href="#存储复杂数据类型"><span>存储复杂数据类型</span></a></h4><p>调用json中的方法将复杂数据类型转换成JSON字符串，再存储到本地</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>JSON.stringify(复杂数据类型)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在取出数据时还需要使用json中的parse函数将json字符串转换为对象</p><h1 id="数组操作" tabindex="-1"><a class="header-anchor" href="#数组操作"><span>数组操作</span></a></h1><h2 id="map" tabindex="-1"><a class="header-anchor" href="#map"><span>map()</span></a></h2><p>map可以遍历数组时处理数据，并且返回处理后的新的数组</p><p>使用map时需要传入一个回调函数,回调函数的第一个参数表示当前元素,第二个参数是当前索引,返回值是修改后要存到新数组里当前位置的值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const arr =[&#39;red&#39;,&#39;blue&#39;,&#39;green&#39;]</span></span>
<span class="line"><span>const newArr = arr.map(function (ele,index) {</span></span>
<span class="line"><span>	console.log(eLe)//数组元素</span></span>
<span class="line"><span>	console.log(index)//数组索引号</span></span>
<span class="line"><span>	return ele+&#39;颜色&#39;</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span>console.log(newArr)    //[&#39;red颜色&#39;,&#39;blue颜色&#39;,&#39;green颜色&#39;］</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="join" tabindex="-1"><a class="header-anchor" href="#join"><span>join()</span></a></h2><p>用于把数组中的所有元素转换一个字符串 参数为一个字符串表示拼接数组中的元素时用什么分隔</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const arr =[&#39;red颜色&#39;,&#39;blue颜色&#39;,&#39;green颜色&#39;]</span></span>
<span class="line"><span>console.log(arr.join(&#39;&#39;))    // red颜色bLue颜色green颜色</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>通常使用这两个函数对数据进行渲染为带html标签的字符串然后再添加到页面中</p>`,75)]))}const p=e(l,[["render",d]]),h=JSON.parse('{"path":"/front/js/3/","title":"3 BOM","lang":"zh-CN","frontmatter":{"title":"3 BOM","createTime":"2025/04/17 09:01:26","permalink":"/front/js/3/"},"readingTime":{"minutes":5.85,"words":1755},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/JavaScript/3 BOM.md","headers":[]}');export{p as comp,h as data};
